# app.py
import json

def lambda_handler(event, context):
    user_data = {
        "userId": "dev-user-id-123",
        "username": "developer",
        "email": "developer@example.com",
        "roles": ["frontend_dev", "tester"],
        "preferences": {
            "theme": "dark",
            "notifications": True
        }
    }

    return {
        "statusCode": 200,
        "headers": {
            "Content-Type": "application/json"
        },
        "body": json.dumps(user_data)
    }

